if (!window._ib2CleanEmpty) {
    window._ib2CleanEmpty = function(html) {
        return html
            .replace(/<p>\s*(<br\s*\/?>)?\s*<\/p>/gi, '')
            .replace(/^(\s*<br\s*\/?>)+/gi, '')
            .replace(/(\s*<br\s*\/?>)+$/gi, '')
            .replace(/(<br\s*\/?>(\s*)){3,}/gi, '<br>');
    };
}

(function() {
    const $ = window.jQuery;

    const MOD = {
        promptId: 'ib2_panel_system',
        cssId: 'ib2-panel-styles',
        expirationDepth: 8,
        contextCleanDepth: 3,

        systemPrompt:
`At the VERY START of every reply — BEFORE any narrative text — output a machine-readable data block inside <ib2_data> tags.
This must be the FIRST thing in your message, on the very first line.

<ib2_data>
SCENE|date=...|weather=...|location=...
TIMELINE|days=N|since=...|event=...|ago=N
CHAR|gender=m or f|name=...|role=...|state=...|outfit=...|where=...
REL|from=...|to=...|reaction=...|mask=...|body=...
</ib2_data>

Then write your narrative response after.

Rules:
- Place <ib2_data> block at the TOP of your reply, before all other text.
- One CHAR line per active character in the scene (speaks, acts, or affects scene this beat). Do NOT include {{user}} — only NPCs and {{char}}.
- Only ONE REL line: from={{char}} to={{user}}. Never write REL from {{user}} to {{char}}.
- body= field in REL is optional, include only if psychosexual toggle is on. Otherwise end at mask=.
- TIMELINE.since = how they relate (met/started dating/etc). Omit entire TIMELINE line if not applicable.
- All values in the same language as the narrative.
- Keep your existing markdown infoblock in the reply as-is — the <ib2_data> is an additional machine-readable mirror.`,

        updatePrompt: '[System Note: Start your reply with <ib2_data>...</ib2_data> block BEFORE any text. Same format. Only {{char}}→{{user}} REL, no reverse. No {{user}} in CHAR lines.]',

        mainRegex: /<ib2_data>([\s\S]*?)<\/ib2_data>/i,

        // patterns that indicate raw ib2 data leaking into DOM
        rawLinePatterns: [
            /^(SCENE|CHAR|REL|TIMELINE)\s*\|/i,
            /\|mask=/i,
            /\|body=/i,
            /\|weather=/i,
            /\|outfit=/i,
            /\|state=/i,
            /\|where=/i,
            /\|since=/i,
        ],
        pipeKvPattern: /\|\w+=/,
    };

    let TH = null;
    const _rendering = {};
    let _contextCleaned = {};
    const _observers = {};

    function esc(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

    function parseBlock(raw) {
        const data = { scene: null, timeline: null, chars: [], rels: [] };
        const lines = raw.split('\n').map(function(l){ return l.trim(); }).filter(Boolean);
        for (var i = 0; i < lines.length; i++) {
            var line = lines[i];
            var pipeIdx = line.indexOf('|');
            if (pipeIdx < 0) continue;
            var type = line.slice(0, pipeIdx).trim().toUpperCase();
            var rest = line.slice(pipeIdx + 1);
            var kv = {};
            rest.split('|').forEach(function(pair) {
                var eq = pair.indexOf('=');
                if (eq < 0) return;
                var k = pair.slice(0, eq).trim().toLowerCase();
                var v = pair.slice(eq + 1).trim();
                if (k && v) kv[k] = v;
            });
            if (type === 'SCENE')         data.scene = kv;
            else if (type === 'TIMELINE') data.timeline = kv;
            else if (type === 'CHAR')     data.chars.push(kv);
            else if (type === 'REL')      data.rels.push(kv);
        }
        return data;
    }

    function hasData(data) {
        return data.scene || data.chars.length || data.rels.length;
    }

    function looksLikeRawData(txt) {
        if (!txt) return false;
        for (var i = 0; i < MOD.rawLinePatterns.length; i++) {
            if (MOD.rawLinePatterns[i].test(txt)) return true;
        }
        return false;
    }

    function looksLikePipeKv(txt) {
        if (!txt) return false;
        var pipes = (txt.match(/\|/g) || []).length;
        var eqs = (txt.match(/\w+=/g) || []).length;
        return pipes >= 2 && eqs >= 2 && MOD.pipeKvPattern.test(txt);
    }

    // ── Aggressive DOM cleaner ──
    function nukeIb2FromDom($target) {
        if (!$target || !$target.length) return;
        var html = $target.html();
        if (!html) return;
        var orig = html;

        // 1) full blocks
        html = html.replace(/(?:<|&lt;)\s*ib2_data\s*(?:>|&gt;)([\s\S]*?)(?:<|&lt;)\s*\/\s*ib2_data\s*(?:>|&gt;)/gi, '');
        // 2) orphaned tags
        html = html.replace(/(?:<|&lt;)\s*\/?\s*ib2_data\s*(?:>|&gt;)/gi, '');
        // 3) raw lines starting with type markers
        html = html.replace(/^[\s]*(?:SCENE|CHAR|REL|TIMELINE)\s*\|[^\n<]*$/gmi, '');
        html = html.replace(/>[\s]*(?:SCENE|CHAR|REL|TIMELINE)\s*\|[^<]*/gi, '>');

        if (html !== orig) {
            html = window._ib2CleanEmpty ? window._ib2CleanEmpty(html) : html;
            $target.html(html.trim());
        }

        // 4) Walk all elements and remove those containing raw data patterns
        $target.find('p, div, span, li, code, pre, blockquote, em, strong, i, b').each(function() {
            var $el = $(this);
            if ($el.closest('.p2-wrap').length) return;
            var txt = $el.text().trim();
            if (/ib2_data/i.test(txt) && txt.length < 20) {
                $el.remove(); return;
            }
            if (looksLikeRawData(txt)) {
                $el.remove(); return;
            }
            // catch blockquote/p that contains pipe-separated key=value (leaked REL content)
            if ($el.is('blockquote, p') && looksLikePipeKv(txt) && txt.length < 500) {
                $el.remove(); return;
            }
        });

        // 5) cleanup
        html = $target.html();
        if (html) {
            var cleaned = window._ib2CleanEmpty ? window._ib2CleanEmpty(html) : html;
            if (cleaned !== html) $target.html(cleaned.trim());
        }
    }

    // ── Streaming observer — hides raw text in real-time during generation ──
    function startStreamObserver(messageId) {
        stopStreamObserver(messageId);
        var $mes = TH.retrieveDisplayedMessage(messageId);
        if (!$mes || !$mes.length) return;
        var $target = $mes.find('.mes_text');
        if (!$target.length) return;
        var node = $target[0];

        var observer = new MutationObserver(function() {
            // hide raw ib2 lines as they stream in
            $target.find('p, div, span, li, code, pre, blockquote, em, strong, i, b').each(function() {
                var $el = $(this);
                if ($el.closest('.p2-wrap').length) return;
                if ($el.data('p2hid')) return;
                var txt = $el.text().trim();
                if (/ib2_data/i.test(txt)) {
                    $el.css('display','none'); $el.data('p2hid', true); return;
                }
                if (looksLikeRawData(txt)) {
                    $el.css('display','none'); $el.data('p2hid', true); return;
                }
                if (looksLikePipeKv(txt) && txt.length < 500) {
                    $el.css('display','none'); $el.data('p2hid', true); return;
                }
            });

            // also hide raw text nodes
            var walker = document.createTreeWalker(node, NodeFilter.SHOW_TEXT, null, false);
            var n;
            while (n = walker.nextNode()) {
                if ($(n).closest('.p2-wrap').length) continue;
                var t = n.textContent.trim();
                if (looksLikeRawData(t) || (/ib2_data/i.test(t))) {
                    if (!n._p2wrap) {
                        var sp = document.createElement('span');
                        sp.style.display = 'none';
                        sp.className = 'p2-stream-hide';
                        n.parentNode.insertBefore(sp, n);
                        sp.appendChild(n);
                        n._p2wrap = true;
                    }
                }
            }
        });

        observer.observe(node, { childList: true, subtree: true, characterData: true });
        _observers[messageId] = observer;
    }

    function stopStreamObserver(messageId) {
        if (_observers[messageId]) {
            _observers[messageId].disconnect();
            delete _observers[messageId];
        }
    }

    // ── Context cleanup ──
    async function cleanContext() {
        if (!TH) return;
        var lastId = TH.getLastMessageId();
        if (lastId < 0) return;
        var msgs = TH.getChatMessages('0-' + lastId);
        if (!msgs) return;
        var updates = [];
        for (var i = 0; i < msgs.length; i++) {
            var msg = msgs[i];
            if (!msg.message) continue;
            var age = lastId - msg.message_id;
            if (age < MOD.contextCleanDepth) continue;
            if (_contextCleaned[msg.message_id]) continue;
            var m = msg.message.match(MOD.mainRegex);
            if (!m) continue;
            var newMsg = msg.message.replace(MOD.mainRegex, '').trim();
            if (newMsg !== msg.message) {
                updates.push({ message_id: msg.message_id, message: newMsg });
                _contextCleaned[msg.message_id] = true;
            }
        }
        if (updates.length > 0) {
            await TH.setChatMessages(updates, { refresh: 'none' });
            console.log('[IB2] context cleaned: ' + updates.length + ' msgs');
        }
    }

    // ── Widget builders ──
    function gIcon(g) {
        g = (g || '').toLowerCase();
        if (g === 'f' || g === 'ж' || g === 'female') return '\u2640';
        if (g === 'm' || g === 'м' || g === 'male')   return '\u2642';
        return '\u25CF';
    }

    function buildScene(s) {
        if (!s) return '';
        var cells = '';
        if (s.date)     cells += '<div class="p2-cell"><span class="p2-lbl">\u0414\u0430\u0442\u0430</span><span class="p2-val">' + esc(s.date) + '</span></div>';
        if (s.weather)  cells += '<div class="p2-cell"><span class="p2-lbl">\u041f\u043e\u0433\u043e\u0434\u0430</span><span class="p2-val">' + esc(s.weather) + '</span></div>';
        if (s.location) cells += '<div class="p2-cell p2-cell--wide"><span class="p2-lbl">\u041c\u0435\u0441\u0442\u043e</span><span class="p2-val">' + esc(s.location) + '</span></div>';
        return '<div class="p2-sec p2-scene">'
            + '<div class="p2-sec-head p2-c-scene">\u0412\u0420\u0415\u041c\u042f</div>'
            + '<div class="p2-scene-grid">' + cells + '</div>'
            + '</div>';
    }

    function buildTimeline(t) {
        if (!t) return '';
        var parts = [];
        if (t.days && t.since) parts.push('\u0414\u043d\u0435\u0439 ' + esc(t.days) + ' \u2014 ' + esc(t.since));
        else if (t.days) parts.push('\u0414\u043d\u0435\u0439 ' + esc(t.days));
        if (t.event) {
            var ev = esc(t.event);
            if (t.ago && t.ago !== '0') ev += ', ' + esc(t.ago) + ' \u0434\u043d. \u043d\u0430\u0437\u0430\u0434';
            parts.push(ev);
        }
        if (!parts.length) return '';
        return '<div class="p2-timeline">' + parts.join('<span class="p2-dot">\u00b7</span>') + '</div>';
    }

    function buildChar(c) {
        var rows = '';
        if (c.state)  rows += '<div class="p2-ck">\u0421\u043e\u0441\u0442\u043e\u044f\u043d\u0438\u0435</div><div class="p2-cv">' + esc(c.state) + '</div>';
        if (c.outfit) rows += '<div class="p2-ck">\u041e\u0434\u0435\u0436\u0434\u0430</div><div class="p2-cv">' + esc(c.outfit) + '</div>';
        if (c.where)  rows += '<div class="p2-ck">\u0413\u0434\u0435</div><div class="p2-cv">' + esc(c.where) + '</div>';
        return '<div class="p2-char">'
            + '<div class="p2-char-name">'
            +   '<span class="p2-gender">' + gIcon(c.gender) + '</span>'
            +   '<span class="p2-name">' + esc(c.name || '?') + '</span>'
            +   (c.role ? '<span class="p2-role">' + esc(c.role) + '</span>' : '')
            + '</div>'
            + (rows ? '<div class="p2-char-grid">' + rows + '</div>' : '')
            + '</div>';
    }

    function buildRel(r) {
        var rows = '';
        if (r.reaction) rows += '<div class="p2-ck">\u0420\u0435\u0430\u043a\u0446\u0438\u044f</div><div class="p2-cv p2-italic">\u00ab' + esc(r.reaction) + '\u00bb</div>';
        if (r.mask)     rows += '<div class="p2-ck">\u041c\u0430\u0441\u043a\u0430</div><div class="p2-cv">' + esc(r.mask) + '</div>';
        if (r.body)     rows += '<div class="p2-ck">\u0422\u0435\u043b\u043e</div><div class="p2-cv p2-body-val">' + esc(r.body) + '</div>';
        return '<div class="p2-rel">'
            + '<div class="p2-rel-pair">'
            +   '<span class="p2-from">' + esc(r.from || '?') + '</span>'
            +   '<span class="p2-arrow">\u2933</span>'
            +   '<span class="p2-to">' + esc(r.to || '?') + '</span>'
            + '</div>'
            + (rows ? '<div class="p2-char-grid">' + rows + '</div>' : '')
            + '</div>';
    }

    function buildWidget(data) {
        var names = data.chars.map(function(c){ return c.name || '?'; }).join(', ');
        var inner = '';
        inner += buildScene(data.scene);
        inner += buildTimeline(data.timeline);
        if (data.chars.length) {
            inner += '<div class="p2-sec">'
                + '<div class="p2-sec-head p2-c-status">\u0421\u0422\u0410\u0422\u0423\u0421</div>'
                + data.chars.map(buildChar).join('')
                + '</div>';
        }
        if (data.rels.length) {
            inner += '<div class="p2-sec">'
                + '<div class="p2-sec-head p2-c-rel">\u041e\u0422\u041d\u041e\u0428\u0415\u041d\u0418\u0415</div>'
                + data.rels.map(buildRel).join('')
                + '</div>';
        }
        return '<details class="p2-wrap">'
            + '<summary class="p2-toggle">'
            +   '<span class="p2-badge">\u0418\u041d\u0424\u041e</span>'
            +   '<span class="p2-toggle-names">' + esc(names) + '</span>'
            + '</summary>'
            + '<div class="p2-content">' + inner + '</div>'
            + '</details>';
    }

    // ── Lifecycle ──
    function getLastState() {
        var lastId = TH.getLastMessageId();
        if (lastId < 1) return null;
        var msgs = TH.getChatMessages('0-' + (lastId - 1));
        if (!msgs) return null;
        for (var i = msgs.length - 1; i >= 0; i--) {
            if (msgs[i].message && MOD.mainRegex.test(msgs[i].message)) return true;
        }
        return null;
    }

    function injectPrompt(has) {
        TH.injectPrompts([{
            id: MOD.promptId, position: 'in_chat', depth: 0, role: 'system',
            content: has ? MOD.updatePrompt : MOD.systemPrompt, should_scan: false,
        }], { once: true });
    }

    function renderVisual(messageId) {
        if (!TH) return;
        if (_rendering[messageId]) return;
        _rendering[messageId] = true;
        setTimeout(function(){ delete _rendering[messageId]; }, 800);

        var msgs = TH.getChatMessages(messageId);
        if (!msgs || !msgs.length || !msgs[0].message) return;
        var raw = msgs[0].message;
        var m = raw.match(MOD.mainRegex);
        if (!m) return;

        var data = parseBlock(m[1]);
        if (!hasData(data)) return;

        var $mes = TH.retrieveDisplayedMessage(messageId);
        if (!$mes || !$mes.length) return;
        var $target = $mes.find('.mes_text').length ? $mes.find('.mes_text') : $mes;
        var lastId = TH.getLastMessageId();
        var expired = (lastId - messageId) >= MOD.expirationDepth;

        // stop any streaming observer
        stopStreamObserver(messageId);

        // remove old widget & hidden spans from streaming
        $target.find('.p2-wrap').remove();
        $target.find('.p2-stream-hide').each(function(){
            var $sh = $(this);
            $sh.children().unwrap();
            $sh.remove();
        });

        // nuke all raw ib2 text
        nukeIb2FromDom($target);

        if (!expired) {
            $target.prepend(buildWidget(data));
        }
    }

    MOD.css = `
.p2-wrap {
    --p2-fg: var(--SmartThemeBodyColor, rgba(255,255,255,0.85));
    --p2-bg: var(--SmartThemeBlurTintColor, rgba(20,20,20,0.65));
    --p2-border: var(--SmartThemeBorderColor, rgba(255,255,255,0.10));
    --p2-quote: var(--SmartThemeQuoteColor, #957C62);
    --p2-em: var(--SmartThemeEmColor, #669E85);
    --p2-accent3: #AB274F;
    display: flex; flex-direction: column;
    font-family: var(--mainFontFamily, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif);
    border-radius: 10px; overflow: hidden;
    border: 1px solid color-mix(in srgb, var(--p2-fg) 10%, transparent);
    background: color-mix(in srgb, var(--p2-fg) 3%, var(--p2-bg));
    margin-bottom: 12px;
    animation: p2-slide .4s cubic-bezier(.16,1,.3,1) both;
    backdrop-filter: blur(8px); -webkit-backdrop-filter: blur(8px);
}
@keyframes p2-slide {
    from { opacity:0; transform:translateY(-6px) }
    to   { opacity:1; transform:translateY(0) }
}
.p2-toggle {
    display: flex; align-items: center; gap: 10px;
    padding: 9px 14px; cursor: pointer; user-select: none; list-style: none;
    background: linear-gradient(135deg,
        color-mix(in srgb, var(--p2-quote) 12%, transparent),
        color-mix(in srgb, var(--p2-em) 6%, transparent));
    transition: background .2s;
}
.p2-toggle::-webkit-details-marker { display:none }
.p2-toggle:hover { background: color-mix(in srgb, var(--p2-fg) 6%, transparent) }
.p2-badge {
    font-size: 9px; font-weight: 800; letter-spacing: .22em;
    color: var(--p2-quote); text-transform: uppercase;
}
.p2-toggle-names {
    flex: 1; text-align: right; font-size: 10px;
    color: color-mix(in srgb, var(--p2-fg) 45%, transparent);
    overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
}
.p2-content { padding: 0; }
.p2-sec {
    padding: 10px 14px;
    border-top: 1px solid color-mix(in srgb, var(--p2-fg) 6%, transparent);
}
.p2-sec:first-child { border-top: none }
.p2-sec-head {
    font-size: 9px; font-weight: 800; letter-spacing: .25em;
    text-transform: uppercase; margin-bottom: 8px;
}
.p2-c-scene  { color: var(--p2-quote) }
.p2-c-status { color: var(--p2-em) }
.p2-c-rel    { color: var(--p2-accent3) }
.p2-scene-grid {
    display: grid; grid-template-columns: 1fr 1fr; gap: 6px;
}
.p2-cell {
    display: flex; flex-direction: column; gap: 2px;
    padding: 6px 8px;
    background: color-mix(in srgb, var(--p2-fg) 3%, transparent);
    border-radius: 6px;
}
.p2-cell--wide { grid-column: 1 / -1 }
.p2-lbl {
    font-size: 8px; font-weight: 700; letter-spacing: .14em;
    text-transform: uppercase;
    color: color-mix(in srgb, var(--p2-fg) 35%, transparent);
}
.p2-val {
    font-size: 11px;
    color: color-mix(in srgb, var(--p2-fg) 80%, transparent);
    line-height: 1.4; overflow-wrap: anywhere;
}
.p2-timeline {
    padding: 7px 14px; font-size: 10px;
    color: color-mix(in srgb, var(--p2-fg) 40%, transparent);
    border-top: 1px solid color-mix(in srgb, var(--p2-fg) 6%, transparent);
    display: flex; align-items: center; gap: 8px; flex-wrap: wrap;
    font-style: italic;
}
.p2-dot { opacity: .4; font-style: normal }
.p2-char {
    padding: 7px 0;
    border-top: 1px dashed color-mix(in srgb, var(--p2-border) 60%, transparent);
}
.p2-char:first-of-type { border-top: none; padding-top: 2px }
.p2-char-name {
    display: flex; align-items: center; gap: 8px; margin-bottom: 5px;
}
.p2-gender { font-size: 13px; color: var(--p2-em); line-height: 1 }
.p2-name {
    font-size: 12px; font-weight: 700;
    color: color-mix(in srgb, var(--p2-fg) 90%, transparent);
}
.p2-role {
    font-size: 9px; font-style: italic;
    color: color-mix(in srgb, var(--p2-fg) 45%, transparent);
    background: color-mix(in srgb, var(--p2-fg) 5%, transparent);
    padding: 1px 7px; border-radius: 20px;
}
.p2-char-grid {
    display: grid; grid-template-columns: auto 1fr;
    column-gap: 10px; row-gap: 3px; align-items: baseline;
    padding-left: 21px;
}
.p2-ck {
    font-size: 8.5px; font-weight: 600; letter-spacing: .1em;
    text-transform: uppercase;
    color: color-mix(in srgb, var(--p2-fg) 32%, transparent);
    white-space: nowrap;
}
.p2-cv {
    font-size: 10.5px;
    color: color-mix(in srgb, var(--p2-fg) 72%, transparent);
    line-height: 1.45; overflow-wrap: anywhere;
}
.p2-italic { font-style: italic }
.p2-body-val { color: color-mix(in srgb, var(--p2-accent3) 80%, var(--p2-fg)) }
.p2-rel {
    padding: 7px 0;
    border-top: 1px dashed color-mix(in srgb, var(--p2-border) 60%, transparent);
}
.p2-rel:first-of-type { border-top: none; padding-top: 2px }
.p2-rel-pair {
    display: flex; align-items: center; gap: 8px;
    margin-bottom: 5px; font-size: 11.5px;
}
.p2-from { color: var(--p2-em); font-weight: 600 }
.p2-arrow {
    font-size: 14px;
    color: color-mix(in srgb, var(--p2-fg) 30%, transparent);
}
.p2-to { color: var(--p2-accent3); font-weight: 600 }
.p2-stream-hide { display: none !important }
@media (max-width: 480px) {
    .p2-scene-grid { grid-template-columns: 1fr }
    .p2-cell--wide { grid-column: auto }
    .p2-toggle-names { display: none }
    .p2-char-grid { padding-left: 0 }
}
`;

    function initializeScript() {
        if (!window.TavernHelper || !window.tavern_events || typeof window.eventOn !== 'function') {
            setTimeout(initializeScript, 200); return;
        }
        TH = window.TavernHelper;
        var ev = window.tavern_events;

        if (!$('#' + MOD.cssId).length) {
            $('head').append('<style id="' + MOD.cssId + '">' + MOD.css + '</style>');
        }

        window.eventOn(ev.CHARACTER_MESSAGE_RENDERED, renderVisual);
        window.eventOn(ev.USER_MESSAGE_RENDERED, renderVisual);
        window.eventOn(ev.MESSAGE_EDITED,  function(id){ setTimeout(function(){ renderVisual(id); }, 120); });
        window.eventOn(ev.MESSAGE_UPDATED, function(id){ setTimeout(function(){ renderVisual(id); }, 120); });
        window.eventOn(ev.MESSAGE_SWIPED,  function(id){ setTimeout(function(){ renderVisual(id); }, 120); });

        var scan = function() {
            $('.mes').each(function(){
                var id = $(this).attr('mesid');
                if (id) renderVisual(Number(id));
            });
        };
        scan();

        window.eventOn(ev.CHAT_CHANGED, function(){ _contextCleaned = {}; setTimeout(scan, 500); });
        window.eventOn(ev.MORE_MESSAGES_LOADED, scan);

        // Before generation: clean old context, inject prompt, start observer
        window.eventOn(ev.GENERATION_AFTER_COMMANDS, function(){
            cleanContext();
            injectPrompt(getLastState());
        });

        // Stream started: attach MutationObserver to last message
        window.eventOn(ev.GENERATION_STARTED, function(){
            setTimeout(function(){
                var lastId = TH.getLastMessageId();
                if (lastId >= 0) startStreamObserver(lastId);
                // also observe next message id in case it hasn't been created yet
                startStreamObserver(lastId + 1);
            }, 300);
        });

        // Also observe on stream token events if available
        if (ev.STREAM_TOKEN_RECEIVED) {
            var _streamObsStarted = {};
            window.eventOn(ev.STREAM_TOKEN_RECEIVED, function(){
                var lastId = TH.getLastMessageId();
                if (!_streamObsStarted[lastId]) {
                    _streamObsStarted[lastId] = true;
                    startStreamObserver(lastId);
                    setTimeout(function(){ delete _streamObsStarted[lastId]; }, 30000);
                }
            });
        }

        window.eventOn(ev.GENERATION_ENDED, function(){
            setTimeout(function(){
                // stop all observers
                for (var k in _observers) stopStreamObserver(k);
                var $l = $('.mes').last();
                var id = $l.attr('mesid');
                if (id) renderVisual(Number(id));
                cleanContext();
            }, 400);
        });
        window.eventOn(ev.GENERATION_STOPPED, function(){
            setTimeout(function(){
                for (var k in _observers) stopStreamObserver(k);
                var $l = $('.mes').last();
                var id = $l.attr('mesid');
                if (id) renderVisual(Number(id));
            }, 400);
        });

        console.log('[IB2] \u2713 infoblock panel v3 init OK');
    }

    $(document).ready(initializeScript);
})();
